frontend.generated_base:
{% extends "_templatify/shell.html" %}

{% block site_main %}
  {% block content %}{% endblock %}
{% endblock %}

{% block body_class %}
{% endblock %}

{% block extra_head %}
{% endblock %}

{% block extra_scripts %}
{% endblock %}

{% block site_header %}
<header class="site-header">
    <nav class="nav">
      <a href="{{ url_for('frontend.home') }}">Home</a>
      <a href="{{ url_for('frontend.news') }}">News</a>
      <a href="{{ url_for('frontend.wiki') }}">Wiki</a>
      <a href="{{ url_for('frontend.community') }}">Community</a>
      <a href="{{ url_for('frontend.game_menu') }}">Game Menu</a>
      {% if session.get("access_token") %}
        {% if session.get("current_user") %}
          <span class="user-info">{{ session["current_user"].get("username", "") }}</span>
        {% endif %}
        <a href="{{ url_for('frontend.dashboard') }}">Dashboard</a>
        <form method="post" action="{{ url_for('frontend.logout') }}">
          <button type="submit">Log out</button>
        </form>
      {% else %}
        <a href="{{ url_for('frontend.login') }}">Login</a>
        <a href="{{ url_for('frontend.register') }}">Register</a>
      {% endif %}
    </nav>
  </header>
{% endblock %}

{% block title %}
World of Shadows
{% endblock %}

